  "inlineSchema": "// ==========================================\n// 知识付费平台 - Prisma 数据库 Schema\n// 开发环境使用 SQLite，生产环境切换为 PostgreSQL\n// ==========================================\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"sqlite\"\n  url      = \"file:./dev.db\"\n}\n\n// 用户模型\nmodel User {\n  id           String    @id @default(uuid())\n  email        String    @unique\n  password     String\n  name         String\n  avatar       String?\n  role         String    @default(\"USER\") // USER / ADMIN\n  isBanned     Boolean   @default(false) // 是否被封号\n  bannedAt     DateTime? // 封号时间\n  bannedReason String? // 封号原因\n  createdAt    DateTime  @default(now())\n  updatedAt    DateTime  @updatedAt\n\n  courses     Course[]     @relation(\"InstructorCourses\")\n  orders      Order[]\n  enrollments Enrollment[]\n  reviews     Review[]\n\n  @@map(\"users\")\n}\n\n// 分类模型\nmodel Category {\n  id          String   @id @default(uuid())\n  name        String   @unique\n  slug        String   @unique\n  description String?\n  sortOrder   Int      @default(0)\n  createdAt   DateTime @default(now())\n\n  courses Course[]\n\n  @@map(\"categories\")\n}\n\n// 课程模型\nmodel Course {\n  id            String   @id @default(uuid())\n  title         String\n  slug          String   @unique\n  description   String?\n  coverImage    String?\n  price         Float    @default(0)\n  originalPrice Float?\n  status        String   @default(\"DRAFT\") // DRAFT / PUBLISHED / ARCHIVED\n  categoryId    String\n  instructorId  String\n  createdAt     DateTime @default(now())\n  updatedAt     DateTime @updatedAt\n\n  category    Category     @relation(fields: [categoryId], references: [id], onDelete: NoAction, onUpdate: Cascade)\n  instructor  User         @relation(\"InstructorCourses\", fields: [instructorId], references: [id], onDelete: NoAction, onUpdate: Cascade)\n  chapters    Chapter[]\n  orders      Order[]\n  enrollments Enrollment[]\n  reviews     Review[]\n\n  @@map(\"courses\")\n}\n\n// 章节模型\nmodel Chapter {\n  id        String   @id @default(uuid())\n  title     String\n  sortOrder Int      @default(0)\n  isFree    Boolean  @default(false)\n  courseId  String\n  createdAt DateTime @default(now())\n\n  course        Course         @relation(fields: [courseId], references: [id], onDelete: Cascade)\n  contentBlocks ContentBlock[] @relation(\"ChapterBlocks\")\n\n  @@map(\"chapters\")\n}\n\n// 内容块模型（支持视频/文章/音频/图片）\nmodel ContentBlock {\n  id        String   @id @default(uuid())\n  type      String // VIDEO / ARTICLE / AUDIO / IMAGE\n  title     String\n  content   String? // 文章正文、图片描述等\n  url       String? // 视频/音频/图片的媒体地址\n  duration  Int? // 视频/音频时长（秒）\n  sortOrder Int      @default(0)\n  chapterId String\n  createdAt DateTime @default(now())\n\n  chapter Chapter @relation(\"ChapterBlocks\", fields: [chapterId], references: [id], onDelete: Cascade)\n\n  @@map(\"content_blocks\")\n}\n\n// 订单模型\nmodel Order {\n  id            String    @id @default(uuid())\n  userId        String\n  courseId      String\n  amount        Float\n  status        String    @default(\"PENDING\") // PENDING / PAID / CANCELLED / REFUNDED\n  paymentMethod String?\n  paidAt        DateTime?\n  refundedAt    DateTime? // 退款时间\n  refundReason  String? // 退款原因\n  createdAt     DateTime  @default(now())\n\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n  course Course @relation(fields: [courseId], references: [id], onDelete: Cascade)\n\n  @@map(\"orders\")\n}\n\n// 报名（学习记录）模型\nmodel Enrollment {\n  id          String    @id @default(uuid())\n  userId      String\n  courseId    String\n  progress    Int       @default(0)\n  completedAt DateTime?\n  createdAt   DateTime  @default(now())\n\n  user            User              @relation(fields: [userId], references: [id], onDelete: Cascade)\n  course          Course            @relation(fields: [courseId], references: [id], onDelete: Cascade)\n  chapterProgress ChapterProgress[]\n\n  @@unique([userId, courseId])\n  @@map(\"enrollments\")\n}\n\n// 章节学习进度模型\nmodel ChapterProgress {\n  id           String    @id @default(uuid())\n  enrollmentId String\n  chapterId    String\n  isCompleted  Boolean   @default(false)\n  completedAt  DateTime?\n  createdAt    DateTime  @default(now())\n\n  enrollment Enrollment @relation(fields: [enrollmentId], references: [id], onDelete: Cascade)\n\n  @@unique([enrollmentId, chapterId])\n  @@map(\"chapter_progress\")\n}\n\n// 评价模型\nmodel Review {\n  id        String   @id @default(uuid())\n  userId    String\n  courseId  String\n  rating    Int\n  comment   String?\n  createdAt DateTime @default(now())\n\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n  course Course @relation(fields: [courseId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, courseId])\n  @@map(\"reviews\")\n}\n",
